noncompliant:
public void Example(bool condition)
{
    if (condition)
        Console.WriteLine("First line"); // Noncompliant: Missing braces
        Console.WriteLine("Second line"); // This is not part of the if!

    for (int i = 0; i < 10; i++)
        if (i % 2 == 0)
            Console.WriteLine(i); // Noncompliant: Nested statements without braces
}

compliant:
public void Example(bool condition)
{
    if (condition)
    {
        Console.WriteLine("First line"); // Compliant: Proper braces
        Console.WriteLine("Second line");
    }

    for (int i = 0; i < 10; i++)
    {
        if (i % 2 == 0)
        {
            Console.WriteLine(i); // Compliant: Proper braces
        }
    }
}
